// ===== Input Validation + Payload Parsing =====
var payload = msg.payload || {};

if (!payload.session_id || typeof payload.session_id !== 'number') {
  msg.payload = JSON.stringify({ code: 1, error: 'session_id is required and must be a number' });
  msg.statusCode = 400;
  return [null, msg];
}
if (!payload.entry_id || typeof payload.entry_id !== 'number') {
  msg.payload = JSON.stringify({ code: 1, error: 'entry_id is required and must be a number' });
  msg.statusCode = 400;
  return [null, msg];
}

msg.session_id = payload.session_id;
msg.entry_id = payload.entry_id;
msg.completion_ratio = Math.min(Math.max(parseFloat(payload.completion_ratio) || 0, 0), 1);
msg.segments = Array.isArray(payload.segments) ? payload.segments : [];

var exerciseSet = msg.segments.filter(function(s) { return s.seg_type === 'WORKOUT_SET'; });
if (exerciseSet.length > 0) {
  msg.exercise = {
    exercise_id: exerciseSet[0].exercise_id,
    planned_sets: exerciseSet.length,
    planned_reps: exerciseSet[0].planned_reps,
    planned_weight: exerciseSet[0].weight_kg_done,
    max_weight: Math.max.apply(null, exerciseSet.map(function(s) { return s.weight_kg_done || 0; }))
  };
}
msg.original_entry_id = payload.entry_id;
return [msg, null];

// ===== 渐进超负荷算法 =====
var exercise = msg.exercise;
var segments = msg.segments;
var completionRatio = msg.completion_ratio;

// 计算平均RPE
var rpeValues = segments.filter(function(s) { return s.rpe != null; }).map(function(s) { return s.rpe; });
var avgRpe = rpeValues.length > 0 ? rpeValues.reduce(function(a,b){return a+b;}) / rpeValues.length : 5;

var newWeight = exercise.planned_weight;
var reason = '';

if (completionRatio >= 1.0 && avgRpe <= 8) {
  newWeight = exercise.planned_weight + 2.5;
  reason = '完成率100%，RPE ' + avgRpe.toFixed(1) + '，递增2.5kg → ' + newWeight + 'kg';
} else if (completionRatio < 0.5) {
  newWeight = Math.max(exercise.planned_weight - 2.5, 0);
  reason = '完成率' + (completionRatio * 100).toFixed(0) + '%，退阶2.5kg → ' + newWeight + 'kg';
} else {
  reason = '完成率' + (completionRatio * 100).toFixed(0) + '%，维持' + exercise.planned_weight + 'kg';
}

// PR检测
var isPR = newWeight > (exercise.max_weight || 0);

// 生成LOCKED提案
var proposal = {
  type: newWeight > exercise.planned_weight ? 'WEIGHT_INCREMENT' : (newWeight < exercise.planned_weight ? 'WEIGHT_DECREMENT' : 'WEIGHT_MAINTAIN'),
  lock_state: 'LOCKED',
  target_table: 'workout_exercise',
  target_id: exercise.exercise_id,
  target_field: 'planned_weight',
  old_value: exercise.planned_weight,
  new_value: newWeight,
  reason: reason,
  is_pr: isPR,
  created_at: new Date().toISOString()
};

msg.payload = {
  newWeight: newWeight,
  reason: reason,
  isPR: isPR,
  proposal: proposal
};
return msg;

var payload = msg.payload || {};
msg.new_entry = {
  entry_id: payload.entry_id,
  date: payload.date,
  start_time: payload.start_time,
  unit_id: payload.unit_id
};
return msg;

var newEntry = msg.new_entry;
var existing = msg.payload || [];

// 检测同时段冲突
var conflicts = existing.filter(function(e) {
  return e.start_time === newEntry.start_time;
});

var proposals = [];

if (conflicts.length > 0) {
  // 获取新条目的优先级
  var newPriority = 5; // 默认
  // 按优先级排序 (数字越小优先级越高)
  var allEntries = conflicts.map(function(e) {
    return { entry_id: e.entry_id, start_time: e.start_time, priority: e.priority || 5, unit_id: e.unit_id };
  });
  allEntries.push({ entry_id: newEntry.entry_id, start_time: newEntry.start_time, priority: newPriority, unit_id: newEntry.unit_id });
  allEntries.sort(function(a, b) { return a.priority - b.priority; });

  // 低优先级项顺延到下一个空档 (每次+60分钟)
  for (var i = 1; i < allEntries.length; i++) {
    var entry = allEntries[i];
    var newTime = addMinutes(entry.start_time, 60 * i);
    proposals.push({
      type: 'PROPOSAL',
      lock_state: 'LOCKED',
      target_table: 'schedule_entry',
      target_id: entry.entry_id,
      target_field: 'start_time',
      old_value: entry.start_time,
      new_value: newTime,
      reason: '时段冲突，自动顺延到 ' + newTime,
      created_at: new Date().toISOString()
    });
  }
}

msg.payload = {
  conflicts: conflicts,
  proposals: proposals,
  resolved: proposals.length > 0
};
return msg;

function addMinutes(timeStr, minutes) {
  var parts = timeStr.split(':');
  var h = parseInt(parts[0]);
  var m = parseInt(parts[1]) + minutes;
  h += Math.floor(m / 60);
  m = m % 60;
  if (h >= 24) h -= 24;
  return ('0' + h).slice(-2) + ':' + ('0' + m).slice(-2);
}

var proposals = msg.payload.proposals || [];
// 为每个提案创建一条SQL
var statements = proposals.map(function(p) {
  return {
    sql: "INSERT INTO proposals (type, lock_state, target_table, target_id, target_field, old_value, new_value, reason, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
    params: [p.type, p.lock_state, p.target_table, p.target_id, p.target_field, p.old_value, p.new_value, p.reason, p.created_at]
  };
});
msg.payload = statements;
return msg;

msg.payload = JSON.stringify({ code: 1, error: msg.error || 'Internal error' });
msg.statusCode = 500;
return msg;

msg.payload = JSON.stringify({ code: 1, error: msg.error || 'Internal error' });
msg.statusCode = 500;
return msg;

// ===== Input Validation + Proposal Action Parsing =====
var proposalId = parseInt(msg.req.params.id, 10);
if (isNaN(proposalId) || proposalId < 1) {
  msg.payload = JSON.stringify({ code: 1, error: 'Invalid proposal ID: must be a positive integer' });
  msg.statusCode = 400;
  return msg;
}

var url = msg.req.url || '';
var lockState, status;
if (url.indexOf('accept') !== -1) {
  lockState = 'ACCEPTED';
  status = 'accepted';
} else {
  lockState = 'REJECTED';
  status = 'rejected';
}
msg.proposal_id = proposalId;
msg.lock_state = lockState;
msg.action_status = status;
return msg;

var status = msg.action_status || 'ok';
msg.payload = JSON.stringify({ code: 0, data: { status: status }, message: 'ok' });
return msg;

msg.payload = JSON.stringify({ code: 1, error: msg.error || 'Internal error' });
msg.statusCode = 500;
return msg;

var week = (msg.req.query && msg.req.query.week) || '';
var startDate, endDate;
function fmt(d) {
  return d.getFullYear() + '-' + ('0'+(d.getMonth()+1)).slice(-2) + '-' + ('0'+d.getDate()).slice(-2);
}
var m = week.match(/^(\d{4})-W(\d{2})$/);
if (m) {
  var year = parseInt(m[1]);
  var weekNum = parseInt(m[2]);
  var simple = new Date(year, 0, 1 + (weekNum - 1) * 7);
  var dow = simple.getDay();
  var monday = new Date(simple);
  if (dow <= 4) { monday.setDate(simple.getDate() - simple.getDay() + 1); }
  else { monday.setDate(simple.getDate() + 8 - simple.getDay()); }
  var sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);
  startDate = fmt(monday) + 'T00:00:00';
  endDate = fmt(sunday) + 'T23:59:59';
} else if (week) {
  startDate = week + 'T00:00:00';
  var e = new Date(week);
  e.setDate(e.getDate() + 6);
  endDate = fmt(e) + 'T23:59:59';
} else {
  var now = new Date();
  var d = now.getDay();
  var monday = new Date(now);
  monday.setDate(now.getDate() - d + 1);
  var sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);
  startDate = fmt(monday) + 'T00:00:00';
  endDate = fmt(sunday) + 'T23:59:59';
}
msg.week_start = startDate;
msg.week_end = endDate;
msg.week = week;
return msg;

var sessions = msg.payload || [];
var totalFocusMinutes = 0;
var totalTrainingVolume = 0;
var completedCount = 0;
sessions.forEach(function(s) {
  if (s.exec_mode === 'FOCUS') {
    totalFocusMinutes += (s.duration_min || (s.completion_ratio || 0) * 25);
  }
  if (s.exec_mode === 'WORKOUT') {
    totalTrainingVolume += (s.total_volume || 0);
  }
  if (s.state === 'COMPLETED') { completedCount++; }
});
var completionRate = sessions.length > 0 ? completedCount / sessions.length : 0;
msg.payload = JSON.stringify({
  code: 0,
  data: {
    week: msg.week,
    start_date: msg.start_date,
    end_date: msg.end_date,
    total_sessions: sessions.length,
    total_focus_minutes: Math.round(totalFocusMinutes),
    total_training_volume: totalTrainingVolume,
    completed_sessions: completedCount,
    completion_rate: Number(completionRate.toFixed(4))
  },
  message: 'ok'
});
return msg;

msg.payload = JSON.stringify({ code: 1, error: msg.error || 'Internal error' });
msg.statusCode = 500;
return msg;

// 检查 SQLite 是否可用
try {
  // 简单的就绪检查: 返回就绪状态
  msg.payload = { code: 0, data: { status: 'ready', checks: { sqlite: 'ok', flows: 'active' } }, message: 'ok' };
  msg.statusCode = 200;
} catch (e) {
  msg.payload = { code: 1, error: e.message };
  msg.statusCode = 503;
}
return msg;

// ===== JWT 登录处理 (安全加固版) =====
var crypto = global.get('crypto');
var fs = global.get('fs');

var JWT_SECRET = global.get('JWT_SECRET');
if (!JWT_SECRET) {
    msg.payload = JSON.stringify({ code: 1, error: '服务器密钥未配置' });
    msg.statusCode = 500;
    return msg;
}

var ACCESS_TOKEN_TTL = 3600;
var REFRESH_TOKEN_TTL = 7 * 24 * 3600;
var REFRESH_FILE = '/data/db/refresh_tokens.json';

function base64url(str) {
    return Buffer.from(str).toString('base64')
        .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}
function base64urlBuf(buf) {
    return buf.toString('base64')
        .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

function signAccessToken(user_id, username) {
    var header = { alg: 'HS256', typ: 'JWT' };
    var now = Math.floor(Date.now() / 1000);
    var payload = { user_id: user_id, username: username, iat: now, exp: now + ACCESS_TOKEN_TTL };
    var headerB64 = base64url(JSON.stringify(header));
    var payloadB64 = base64url(JSON.stringify(payload));
    var data = headerB64 + '.' + payloadB64;
    var sig = crypto.createHmac('sha256', JWT_SECRET).update(data).digest();
    return data + '.' + base64urlBuf(sig);
}

function generateRefreshToken() {
    return crypto.randomBytes(64).toString('hex');
}

// scrypt 密码验证 (timing-safe)
function verifyPassword(password, storedHash) {
    var parts = storedHash.split(':');
    if (parts.length !== 2) return false;
    var salt = Buffer.from(parts[0], 'hex');
    var hash = Buffer.from(parts[1], 'hex');
    var computedHash = crypto.scryptSync(password, salt, 64);
    if (hash.length !== computedHash.length) return false;
    return crypto.timingSafeEqual(hash, computedHash);
}

// 用户库 (密码使用 scrypt 哈希存储, 非明文)
var users = [
    { user_id: 1, username: 'admin', password_hash: '***REMOVED***:***REMOVED***' }
];

var body = msg.payload || {};
var username = body.username;
var password = body.password;

if (!username || !password) {
    msg.payload = JSON.stringify({ code: 1, error: '用户名和密码不能为空' });
    msg.statusCode = 400;
    return msg;
}

// 查找用户并验证密码 (scrypt + timingSafeEqual, 防时序攻击)
var user = null;
for (var i = 0; i < users.length; i++) {
    if (users[i].username === username) {
        if (verifyPassword(password, users[i].password_hash)) {
            user = users[i];
        }
        break;
    }
}

if (!user) {
    msg.payload = JSON.stringify({ code: 1, error: '用户名或密码错误' });
    msg.statusCode = 401;
    return msg;
}

var accessToken = signAccessToken(user.user_id, user.username);
var refreshToken = generateRefreshToken();

// 持久化 Refresh Token 到文件系统 (容器重启后不丢失)
var refreshStore = {};
try {
    refreshStore = JSON.parse(fs.readFileSync(REFRESH_FILE, 'utf8') || '{}');
} catch (e) { /* 文件不存在, 使用空存储 */ }

var now = Math.floor(Date.now() / 1000);
refreshStore[refreshToken] = {
    user_id: user.user_id,
    username: user.username,
    created_at: now,
    expires_at: now + REFRESH_TOKEN_TTL
};

try {
    fs.writeFileSync(REFRESH_FILE, JSON.stringify(refreshStore));
} catch (e) {
    global.set('refresh_tokens', refreshStore);
}

msg.payload = JSON.stringify({
    access_token: accessToken,
    refresh_token: refreshToken,
    token_type: 'Bearer',
    expires_in: ACCESS_TOKEN_TTL
});
msg.statusCode = 200;
return msg;

// ===== JWT 刷新处理 (持久化版) =====
var crypto = global.get('crypto');
