var authHeader = msg.req.headers['authorization'] || '';
var token = '';
if (authHeader.indexOf('Bearer ') === 0) {
    token = authHeader.substring(7);
}

if (!token) {
    msg.payload = JSON.stringify({ code: 1, error: '缺少 Refresh Token' });
    msg.statusCode = 401;
    return msg;
}

// 从文件读取 Refresh Token 存储 (持久化)
var refreshStore = {};
try {
    refreshStore = JSON.parse(fs.readFileSync(REFRESH_FILE, 'utf8') || '{}');
} catch (e) {
    refreshStore = global.get('refresh_tokens') || {};
}

var tokenData = refreshStore[token];

if (!tokenData) {
    msg.payload = JSON.stringify({ code: 1, error: '无效的 Refresh Token' });
    msg.statusCode = 401;
    return msg;
}

var now = Math.floor(Date.now() / 1000);
if (now > tokenData.expires_at) {
    delete refreshStore[token];
    try { fs.writeFileSync(REFRESH_FILE, JSON.stringify(refreshStore)); } catch(e) { global.set('refresh_tokens', refreshStore); }
    msg.payload = JSON.stringify({ code: 1, error: 'Refresh Token 已过期, 请重新登录' });
    msg.statusCode = 401;
    return msg;
}

var accessToken = signAccessToken(tokenData.user_id, tokenData.username);

msg.payload = JSON.stringify({
    access_token: accessToken,
    refresh_token: token,
    token_type: 'Bearer',
    expires_in: ACCESS_TOKEN_TTL
});
msg.statusCode = 200;
return msg;

// ===== JWT 验证处理 =====
var crypto = global.get('crypto');

var JWT_SECRET = global.get('JWT_SECRET');
if (!JWT_SECRET) {
    msg.payload = JSON.stringify({ code: 1, error: '服务器密钥未配置' });
    msg.statusCode = 500;
    return msg;
}

function base64urlDecode(str) {
    str = str.replace(/-/g, '+').replace(/_/g, '/');
    while (str.length % 4) { str += '='; }
    return str;
}

var authHeader = msg.req.headers['authorization'] || '';
var token = '';
if (authHeader.indexOf('Bearer ') === 0) {
    token = authHeader.substring(7);
}

if (!token) {
    msg.payload = JSON.stringify({ code: 1, error: '缺少 Access Token' });
    msg.statusCode = 401;
    return msg;
}

var parts = token.split('.');
if (parts.length !== 3) {
    msg.payload = JSON.stringify({ code: 1, error: '令牌格式无效' });
    msg.statusCode = 401;
    return msg;
}

var headerB64 = parts[0];
var payloadB64 = parts[1];
var signatureB64 = parts[2];
var data = headerB64 + '.' + payloadB64;

var expectedSig = crypto.createHmac('sha256', JWT_SECRET).update(data).digest();
var expectedSigB64 = expectedSig.toString('base64')
    .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');

if (expectedSigB64.length !== signatureB64.length) {
    msg.payload = JSON.stringify({ code: 1, error: '令牌签名无效' });
    msg.statusCode = 401;
    return msg;
}
var diff = 0;
for (var i = 0; i < expectedSigB64.length; i++) {
    diff |= expectedSigB64.charCodeAt(i) ^ signatureB64.charCodeAt(i);
}
if (diff !== 0) {
    msg.payload = JSON.stringify({ code: 1, error: '令牌签名无效' });
    msg.statusCode = 401;
    return msg;
}

var payloadStr = Buffer.from(base64urlDecode(payloadB64), 'base64').toString();
var payload;
try {
    payload = JSON.parse(payloadStr);
} catch (e) {
    msg.payload = JSON.stringify({ code: 1, error: '令牌负载解析失败' });
    msg.statusCode = 401;
    return msg;
}

var now = Math.floor(Date.now() / 1000);
if (payload.exp && now > payload.exp) {
    msg.payload = JSON.stringify({ code: 1, error: '令牌已过期' });
    msg.statusCode = 401;
    return msg;
}

msg.payload = JSON.stringify({
    code: 0,
    data: {
        valid: true,
        user_id: payload.user_id,
        username: payload.username,
        exp: payload.exp,
        iat: payload.iat
    },
    message: '令牌有效'
});
msg.statusCode = 200;
return msg;

// 错误格式化: 捕获 Flow 执行异常, 返回统一错误响应
var errMsg = msg.error ? msg.error.message : '认证服务内部错误';
msg.payload = JSON.stringify({ code: 1, error: errMsg });
msg.statusCode = 500;
return msg;

// 渲染 Prometheus 文本格式指标
var m = global.get('ff_metrics');
if (!m) {
    m = {
        sessions_total: {},
        session_duration: {},
        proposals_total: {},
        api_requests_total: {},
        api_request_duration: {},
        sync_queue_size: 0
    };
    global.set('ff_metrics', m);
}

var DURATION_BUCKETS = [60, 300, 600, 900, 1800, 3600, 5400, 7200];
var API_DURATION_BUCKETS = [0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10];
var lines = [];

// 1. 会话总数计数器
lines.push('# HELP focus_fitness_sessions_total 会话总数计数器');
lines.push('# TYPE focus_fitness_sessions_total counter');
for (var key in m.sessions_total) {
    var parts = key.split('|');
    lines.push('focus_fitness_sessions_total{type="' + parts[0] + '",status="' + parts[1] + '"} ' + m.sessions_total[key]);
}

// 2. 会话时长直方图
lines.push('');
lines.push('# HELP focus_fitness_session_duration_seconds 会话时长直方图 (秒)');
lines.push('# TYPE focus_fitness_session_duration_seconds histogram');
for (var type in m.session_duration) {
    var h = m.session_duration[type];
    for (var i = 0; i < DURATION_BUCKETS.length; i++) {
        var le = DURATION_BUCKETS[i];
        lines.push('focus_fitness_session_duration_seconds_bucket{type="' + type + '",le="' + le + '"} ' + (h.buckets[le] || 0));
    }
    lines.push('focus_fitness_session_duration_seconds_bucket{type="' + type + '",le="+Inf"} ' + h.count);
    lines.push('focus_fitness_session_duration_seconds_count{type="' + type + '"} ' + h.count);
    lines.push('focus_fitness_session_duration_seconds_sum{type="' + type + '"} ' + h.sum);
}

// 3. 提案总数
lines.push('');
lines.push('# HELP focus_fitness_proposals_total 提案总数计数器');
lines.push('# TYPE focus_fitness_proposals_total counter');
for (var key in m.proposals_total) {
    lines.push('focus_fitness_proposals_total{status="' + key + '"} ' + m.proposals_total[key]);
}

// 4. API 请求总数
lines.push('');
lines.push('# HELP focus_fitness_api_requests_total API 请求总数计数器');
lines.push('# TYPE focus_fitness_api_requests_total counter');
for (var key in m.api_requests_total) {
    var parts = key.split('|');
    lines.push('focus_fitness_api_requests_total{endpoint="' + parts[0] + '",status="' + parts[1] + '"} ' + m.api_requests_total[key]);
}

// 5. API 请求延迟直方图
lines.push('');
lines.push('# HELP focus_fitness_api_request_duration_seconds API 请求延迟直方图 (秒)');
lines.push('# TYPE focus_fitness_api_request_duration_seconds histogram');
for (var endpoint in m.api_request_duration) {
    var h = m.api_request_duration[endpoint];
    for (var i = 0; i < API_DURATION_BUCKETS.length; i++) {
        var le = API_DURATION_BUCKETS[i];
        lines.push('focus_fitness_api_request_duration_seconds_bucket{endpoint="' + endpoint + '",le="' + le + '"} ' + (h.buckets[le] || 0));
    }
    lines.push('focus_fitness_api_request_duration_seconds_bucket{endpoint="' + endpoint + '",le="+Inf"} ' + h.count);
    lines.push('focus_fitness_api_request_duration_seconds_count{endpoint="' + endpoint + '"} ' + h.count);
    lines.push('focus_fitness_api_request_duration_seconds_sum{endpoint="' + endpoint + '"} ' + h.sum);
}

// 6. 同步队列大小 (gauge)
lines.push('');
lines.push('# HELP focus_fitness_sync_queue_size 同步队列大小');
lines.push('# TYPE focus_fitness_sync_queue_size gauge');
lines.push('focus_fitness_sync_queue_size ' + m.sync_queue_size);

msg.payload = lines.join('\n') + '\n';
msg.headers = {'Content-Type': 'text/plain; version=0.0.4; charset=utf-8'};
return msg;

